import{_ as e,o as t,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F12: 研發產出比與技術變現率","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F12_研發產出比與技術變現率_投資研究員.md","filePath":"32Ｑ題本＿重要/財務組/F12_研發產出比與技術變現率_投資研究員.md"}'),i={name:"32Ｑ題本＿重要/財務組/F12_研發產出比與技術變現率_投資研究員.md"};function l(s,n,a,g,c,d){return t(),o("div",null,[...n[0]||(n[0]=[r('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f12-研發產出比與技術變現率" tabindex="-1">F12: 研發產出比與技術變現率 <a class="header-anchor" href="#f12-研發產出比與技術變現率" aria-label="Permalink to &quot;F12: 研發產出比與技術變現率&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F12</li><li><strong>題目：</strong> 近三年研發費用 (R&amp;D) 投入與實際營收/獲利產出的關聯性為何？技術轉化效率是否正在改善？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「技術資本化分析」與智慧財產 (IP) 價值評估。擅長計算「研發產出率 (R&amp;D Yield)」與技術生命週期，識別企業是在進行引領行業的「突破性創新」，還是在為維持競爭力而進行的「防禦性研發燒錢」。</li><li><strong>意圖：</strong> 執行「技術 ROI 與創新驅動審計」，判定公司研發投資是否實質轉化為毛利率提升或市佔率擴張，識別長期「研發虛耗」與「技術路徑錯誤」風險。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockFinancialStatements</code> 提取 <code>ResearchAndDevelopmentExpense</code> (研發費用)。計算「研發費用率 (R&amp;D Intensity)」。</li><li><strong>【外部事實確認：Google Search】</strong>：檢索「[公司名] 新產品上市」、「[公司名] 專利獲權數量」、「[公司名] 技術領先地位 評論」。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱「業務概況 -&gt; 研究發展」節，詳列「主要研發成果」與「未來五年開發計畫」之進度與預計量產時間。</li></ol></li><li><strong>邏輯：</strong> 執行「技術變現算則」——分析研發費用成長與次年「新產品營收貢獻度」的連動性；執行「研發槓桿測算」分析單位研發支出創造的營業利潤增量。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>取數據</strong>：<code>python3 數據採集器.py finance [股號]</code> → 抓 ResearchAndDevelopmentExpense</li><li><strong>計算研發強度</strong>：研發費用 / 營收。若 ❤️% 需註明產業特性差異</li><li><strong>判讀</strong>：對比同業研發費用率，非製造業研發低屬正常</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①專家評析 ≥200 字；②空頭視角 ≥2 個（低研發壁壘是重要利空）；③注意產業特性勿誤判</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【研發事實優先】</strong>：智慧體<strong>必須</strong>列出近三年的「研發費用額」及其佔營收比重。禁止在未列出投入強度前給予「技術優勢」之讚譽。</li><li><strong>【變現效率偵測】</strong>：智慧體必須對比「研發強度」與「毛利率趨勢」。若研發投入增加但毛利率連續四季下滑，必須強制標註「研發轉化無效」或「技術路徑脫節」風險。</li><li><strong>【創新含金量審核】</strong>：檢索是否有「顛覆性技術」投產的消息。判定研發是屬於「微幅改良」還是「跨世代升級」。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述指標】</strong>：絕對禁用「重視研發」、「成果輝煌」。必須量化為具體的「研發產出倍數 (Revenue/R&amp;D)」與「技術生命週期 (Months)」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f12-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【F12 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【f12-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【F12 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「研發強度+轉化鑑定」結構（例：R&amp;D 佔比 X%，帶動 Y% 毛利增長，判定技術變現 [高效/滯後]，技術護城河 [擴張/萎縮]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：研發投入精準轉化為市場領先的高毛利產品，研發產出率持續攀升，且具備專利保護牆，技術變現動能極強。</li><li><strong>A (良)</strong>：研發投入與成長規模匹配，能穩定推出次世代產品以維持競爭力，技術轉化路徑清晰且獲利穩定。</li><li><strong>B (持平)</strong>：陷入「研發黑洞」——研發支出巨大但營收成長停滯，或新產品市場反應冷淡，面臨超重的資本虛耗與技術落後風險。</li></ul></li><li><strong>【答詢詳解】解析深度</strong>：依照以下三個維度回答： <ol><li><strong>研發槓桿分析 (R&amp;D Leverage Audit)</strong>：分析單位研發投入對營業利益的成長拉動力。</li><li><strong>技術路徑競爭力 (Tech Path Competitiveness)</strong>：對比同業分析該公司在技術規格上的實質領先優勢。</li><li><strong>專利質量與變現 (IP Value Monetization)</strong>：評估企業 IP 組合的變現潛力與法律侵權風險。</li></ol></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 FinMind <code>financial</code> 損益表科目與年報 P.XXX 研發專案進度表。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：特別關注「研發費用資本化」之比例。若公司將大量研發支出列為「無形資產」而非費用，專家應在此處診斷為「財報美化風險」。</li></ul>',12)])])}const p=e(i,[["render",l]]);export{h as __pageData,p as default};
